// ===================================================
// getPartnerBookings 파라미터 검증
// ===================================================

const _body = $input.first().json.body || {};
const _rawQuery = $input.first().json.query || {};
// POST body 우선, 없으면 query string, 없으면 직접 json
const query = Object.keys(_body).length > 0 ? _body 
             : (Object.keys(_rawQuery).length > 0 ? _rawQuery 
             : $input.first().json);
const memberId = (query.member_id || '').trim();

if (!memberId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'NOT_LOGGED_IN', message: '로그인이 필요합니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

const classId = (query.class_id || '').trim();
const dateFrom = (query.date_from || '').trim();
const dateTo = (query.date_to || '').trim();
const page = Math.max(parseInt(query.page) || 1, 1);
const limit = Math.min(Math.max(parseInt(query.limit) || 20, 1), 50);

// 날짜 형식 검증 (YYYY-MM-DD)
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (dateFrom && !dateRegex.test(dateFrom)) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'MISSING_PARAMS', message: 'date_from은 YYYY-MM-DD 형식이어야 합니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}
if (dateTo && !dateRegex.test(dateTo)) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'MISSING_PARAMS', message: 'date_to는 YYYY-MM-DD 형식이어야 합니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    memberId,
    classId,
    dateFrom,
    dateTo,
    page,
    limit,
    _error: false
  }
}];

// ===================================================
// 파트너 인증 확인 + where 파라미터 구성
// ===================================================

const response = $input.first().json;
const partnerList = response.list || [];
const params = $('Parse Bookings Params').first().json;

if (partnerList.length === 0) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'NOT_PARTNER', message: '파트너로 등록되지 않은 회원입니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

const p = partnerList[0];
if (p.status !== 'active') {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'PARTNER_INACTIVE', message: '비활성 상태의 파트너 계정입니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

let whereParts = [`(partner_code,eq,${p.partner_code})`];
if (params.classId) {
  whereParts.push(`(class_id,eq,${params.classId})`);
}

return [{
  json: {
    _error: false,
    partnerCode: p.partner_code,
    where: whereParts.join('~and'),
    page: params.page,
    limit: params.limit,
    dateFrom: params.dateFrom,
    dateTo: params.dateTo
  }
}];

// ===================================================
// 예약 목록 응답 구성: 수강생 정보 마스킹 + 페이징 + 집계
// ===================================================

const classesData = $input.first().json;
const settlementsData = $('NocoDB Get Settlements (Bookings)').first().json;
const authData = $('Auth & Build Where (Bookings)').first().json;

function maskPhone(phone) {
  if (!phone) return '';
  const clean = String(phone).replace(/[^0-9]/g, '');
  if (clean.length < 10) return phone;
  return clean.substring(0, 3) + '-****-' + clean.substring(clean.length - 4);
}

function maskName(name) {
  if (!name) return '';
  if (name.length <= 1) return name + '*';
  return name.charAt(0) + '*'.repeat(name.length - 1);
}

function maskEmail(email) {
  if (!email || !email.includes('@')) return email || '';
  const parts = email.split('@');
  const local = parts[0] || '';
  const domain = parts[1] || '';
  const visible = local.substring(0, Math.min(3, local.length));
  return visible + '***@' + domain;
}

function dateOnly(value) {
  return String(value || '').substring(0, 10);
}

function extractClassId(value) {
  if (Array.isArray(value) && value.length > 0) {
    return value[0].class_id || value[0].Title || '';
  }
  if (typeof value === 'string') {
    return value;
  }
  return '';
}

const classNameMap = {};
(classesData.list || []).forEach(function(c) {
  if (c.class_id) {
    classNameMap[c.class_id] = c.class_name || c.title || c.class_id;
  }
});

const allSettlements = settlementsData.list || [];
const filteredSettlements = allSettlements.filter(function(row) {
  const rowDate = dateOnly(row.class_date || row.created_date || row.CreatedAt || '');
  if (authData.dateFrom && (!rowDate || rowDate < authData.dateFrom)) {
    return false;
  }
  if (authData.dateTo && (!rowDate || rowDate > authData.dateTo)) {
    return false;
  }
  return true;
});

let completedCount = 0;
let pendingCount = 0;
const bookings = filteredSettlements.map(function(s) {
  const status = String(s.status || '').toUpperCase();
  if (status === 'COMPLETED') completedCount++;
  else if (status === 'PENDING' || status === 'PROCESSING' || status === 'PENDING_SETTLEMENT') pendingCount++;

  const classId = extractClassId(s.class_id);

  return {
    settlement_id: s.settlement_id || '',
    order_id: s.order_id || '',
    class_id: classId,
    class_name: classNameMap[classId] || '',
    booking_date: dateOnly(s.class_date || s.created_date || s.CreatedAt || ''),
    schedule_date: dateOnly(s.class_date || ''),
    student_name_masked: maskName(s.student_name || ''),
    student_email_masked: maskEmail(s.student_email || ''),
    student_phone_masked: maskPhone(s.student_phone || ''),
    student_count: Number(s.student_count) || 1,
    order_amount: Number(s.order_amount) || 0,
    commission_amount: Number(s.commission_amount) || 0,
    reserve_amount: Number(s.reserve_amount) || 0,
    status: status,
    created_date: s.created_date || s.CreatedAt || ''
  };
});

const totalCount = bookings.length;
const page = authData.page;
const limit = authData.limit;
const totalPages = totalCount > 0 ? Math.ceil(totalCount / limit) : 0;
const startIdx = (page - 1) * limit;
const pagedBookings = bookings.slice(startIdx, startIdx + limit);

return [{
  json: {
    success: true,
    data: {
      bookings: pagedBookings,
      summary: {
        total_count: totalCount,
        completed_count: completedCount,
        pending_count: pendingCount,
        failed_count: totalCount - completedCount - pendingCount
      },
      pagination: {
        page: page,
        limit: limit,
        total_count: totalCount,
        total_pages: totalPages
      }
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// getPartnerReviews 파라미터 검증
// ===================================================

const _body = $input.first().json.body || {};
const _rawQuery = $input.first().json.query || {};
// POST body 우선, 없으면 query string, 없으면 직접 json
const query = Object.keys(_body).length > 0 ? _body 
             : (Object.keys(_rawQuery).length > 0 ? _rawQuery 
             : $input.first().json);
const memberId = (query.member_id || '').trim();

if (!memberId) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'NOT_LOGGED_IN', message: '로그인이 필요합니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

const classId = (query.class_id || '').trim();
const page = Math.max(parseInt(query.page) || 1, 1);
const limit = Math.min(Math.max(parseInt(query.limit) || 10, 1), 50);

return [{
  json: {
    memberId,
    classId,
    page,
    limit,
    _error: false
  }
}];

// ===================================================
// 파트너 인증 + 후기 조회 where 구성
// ===================================================

const response = $input.first().json;
const partnerList = response.list || [];
const params = $('Parse Reviews Params').first().json;

if (partnerList.length === 0) {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'NOT_PARTNER', message: '파트너로 등록되지 않은 회원입니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

const p = partnerList[0];
if (p.status !== 'active') {
  return [{
    json: {
      _error: true,
      success: false,
      error: { code: 'PARTNER_INACTIVE', message: '비활성 상태의 파트너 계정입니다.' },
      timestamp: new Date().toISOString()
    }
  }];
}

// where 조건: partner_code 기준 + class_id 필터
let whereParts = [`(partner_code,eq,${p.partner_code})`];
if (params.classId) {
  whereParts.push(`(class_id,eq,${params.classId})`);
}

return [{
  json: {
    _error: false,
    partnerCode: p.partner_code,
    where: whereParts.join('~and'),
    page: params.page,
    limit: params.limit
  }
}];

// ===================================================
// 후기 목록 응답 구성: 별점 분포 + 마스킹 + 페이징
// ===================================================

const classesData = $input.first().json;
const reviewsResponse = $('NocoDB Get Reviews').first().json;
const authData = $('Auth & Build Where (Reviews)').first().json;

function maskName(name) {
  if (!name) return '';
  if (name.length <= 1) return name + '*';
  return name.charAt(0) + '*'.repeat(name.length - 1);
}

function extractClassId(value) {
  if (Array.isArray(value) && value.length > 0) {
    return value[0].class_id || value[0].Title || '';
  }
  if (typeof value === 'string') {
    return value;
  }
  return '';
}

const classNameMap = {};
(classesData.list || []).forEach(function(c) {
  if (c.class_id) {
    classNameMap[c.class_id] = c.class_name || '';
  }
});

const reviewsList = reviewsResponse.list || [];
let totalRating = 0;
const ratingDist = { 5: 0, 4: 0, 3: 0, 2: 0, 1: 0 };
let answeredCount = 0;
let unansweredCount = 0;

const reviews = reviewsList.map(function(r) {
  const rating = Number(r.rating) || 0;
  totalRating += rating;
  if (rating >= 1 && rating <= 5) {
    ratingDist[rating] = (ratingDist[rating] || 0) + 1;
  }

  const hasAnswer = String(r.partner_answer || '').trim().length > 0;
  if (hasAnswer) answeredCount++;
  else unansweredCount++;

  const classId = extractClassId(r.class_id);

  return {
    review_id: r.review_id || '',
    class_id: classId,
    class_name: classNameMap[classId] || '',
    reviewer_name_masked: maskName(r.reviewer_name || ''),
    rating: rating,
    content: r.content || '',
    image_urls: r.image_urls || '',
    created_at: r.created_at || r.CreatedAt || '',
    partner_answer: r.partner_answer || '',
    answer_at: r.answer_at || '',
    has_answer: hasAnswer
  };
});

const totalCount = reviews.length;
const page = authData.page;
const limit = authData.limit;
const totalPages = totalCount > 0 ? Math.ceil(totalCount / limit) : 0;
const startIdx = (page - 1) * limit;
const pagedReviews = reviews.slice(startIdx, startIdx + limit);
const avgRating = totalCount > 0 ? Math.round((totalRating / totalCount) * 10) / 10 : 0;

return [{
  json: {
    success: true,
    data: {
      reviews: pagedReviews,
      summary: {
        total_count: totalCount,
        avg_rating: avgRating,
        rating_distribution: ratingDist,
        answered_count: answeredCount,
        unanswered_count: unansweredCount
      },
      pagination: {
        page: page,
        limit: limit,
        total_count: totalCount,
        total_pages: totalPages
      }
    },
    timestamp: new Date().toISOString()
  }
}];

// Fallback: 알 수 없는 action
const body = $input.first().json.body || {};
const query = $input.first().json.query || {};
const action = body.action || query.action || $input.first().json.action || '';
return [{
  json: {
    success: false,
    error: {
      code: 'INVALID_ACTION',
      message: `알 수 없는 요청입니다: ${action}`
    },
    timestamp: new Date().toISOString()
  }
}];
